  ('elementary-0c700c30-moex-00328', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-932665b2', 'sub-elementary-0c700c30-03', NULL, 'single_choice', '已知大臺北地區出版業公司之員工人數呈常態分配，平均人數為25人，標準差未知。今隨機抽取15 家出版公司為樣本，計算得其員工人數的標準差為3人，若欲計算此15家公司的平均員工人數超過 27人的機率，應使用何種分配？', '["常態分配", "t分配", "卡方分配", "F分配"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "714e6cc78a19", "answer_pdf_sha1": "21c652325cc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "統計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
